const CONFIG = {
  SPREADSHEET_ID: '1kwXtpKxtQE52lFnz5MRRV0dnzeftN_X5tD69CL12ycU',
  SHEET_IDS: {
    CONFIG: 1170756615,
    MATCHES: 996094587,
    WATCHLIST: 715101038,
    RECOMMENDATIONS: 532487099,
  },
  TIMEZONE: 'Asia/Seoul',
  MATCH_DURATION_MINUTES: 120,
  MATCH_END_GRACE_MINUTES: 1,
  FUTURE_WINDOW_MINUTES: 1,
  MIN_MINUTE: 5,
  MAX_MINUTE: 85,
  SECOND_HALF_START_MINUTE: 5,
  ONLY_LIVE: true,
  MIN_CONFIDENCE: 5,
  EMAIL_TO: 'huynhxuanthi@gmail.com',
  BOOKMAKERS_PRIORITY: 'ALL',
  AI_PROVIDER: 'gemini', 
  AI_MODEL: 'gemini-3.0-flash',
  AI_TEMPERATURE: '1.0',
  AI_MAX_TOKENS: '1024',
  AI_PROMPT_VERSION: '0.1',
};

// ============================================================
// NEW: Read webhook params for manual push support
// ============================================================
let webhookParams = {
  match_id: null,
  match_ids: [],
  force: false,
  is_manual_push: false,
};

try {
  const wb = $("Webhook").first().json || {};
  const body = wb.body || {};

  if (body.match_id) {
    webhookParams.match_id = String(body.match_id);
    webhookParams.match_ids = [String(body.match_id)];
  } else if (Array.isArray(body.match_ids) && body.match_ids.length > 0) {
    webhookParams.match_ids = body.match_ids.map(id => String(id));
  } else if (Array.isArray(body.liveMatchIds) && body.liveMatchIds.length > 0) {
    webhookParams.match_ids = body.liveMatchIds.map(id => String(id));
  }

  webhookParams.force = body.force === true;
  webhookParams.is_manual_push = webhookParams.match_ids.length > 0;

  if (webhookParams.is_manual_push) {
    console.log(`[Set Config] Manual push detected: ${webhookParams.match_ids.length} match(es), force=${webhookParams.force}`);
  }
} catch (e) {
  console.log("[Set Config] No webhook body or error reading:", e.message);
}

return { 
  json: { 
    ...CONFIG, 
    webhook_params: webhookParams,
    is_manual_push: webhookParams.is_manual_push,
  } 
};

const allMatches = $input.all();
if (!allMatches.length) {
  return [];
}

let config = {};
const cfgNode = $("Set Config");
if (cfgNode && cfgNode.length > 0) {
  config = cfgNode.first().json || {};
}

const TIMEZONE = config.TIMEZONE || "UTC";
const MATCH_DURATION_MINUTES = Number(config.MATCH_DURATION_MINUTES ?? 120);
const MATCH_END_GRACE_MINUTES = Number(config.MATCH_END_GRACE_MINUTES ?? 5);
const FUTURE_WINDOW_MINUTES = Number(config.FUTURE_WINDOW_MINUTES ?? 1);

// ============================================================
// NEW: Read webhook params from Set Config
// ============================================================
const webhookParams = config.webhook_params || {};
const forceAnalyze = webhookParams.force === true;
const isManualPush = webhookParams.is_manual_push === true;

let liveIds = webhookParams.match_ids || [];

if (liveIds.length === 0) {
  try {
    const wb = $("Webhook").first().json || {};
    const body = wb.body || {};
    if (Array.isArray(body.liveMatchIds)) {
      liveIds = body.liveMatchIds.map(id => String(id));
    }
  } catch (e) {
    console.log("[Filter Active Only] Cannot read liveMatchIds from Webhook:", e.message);
  }
}

function parseLocalDateTime(dateStr, timeStr) {
  if (!dateStr) return null;
  const dateParts = String(dateStr).trim().split("-");
  if (dateParts.length !== 3) return null;
  const year = Number(dateParts[0]);
  const month = Number(dateParts[1]);
  const day = Number(dateParts[2]);
  let hour = 0;
  let minute = 0;
  if (timeStr) {
    const tParts = String(timeStr).trim().split(":");
    hour = Number(tParts[0] || 0);
    minute = Number(tParts[1] || 0);
  }
  if (!year || !month || !day) return null;
  return new Date(Date.UTC(year, month - 1, day, hour, minute, 0, 0));
}

const now = new Date();
const formatter = new Intl.DateTimeFormat("en-GB", {
  timeZone: TIMEZONE,
  year: "numeric",
  month: "2-digit",
  day: "2-digit",
  hour: "2-digit",
  minute: "2-digit",
  hour12: false,
});
const parts = formatter.formatToParts(now);
const part = (type) => Number(parts.find((p) => p.type === type).value);
const nowLocal = new Date(
  Date.UTC(
    part("year"),
    part("month") - 1,
    part("day"),
    part("hour"),
    part("minute"),
    0,
    0
  )
);

let relevant = [];

if (liveIds.length > 0) {
  const idSet = new Set(liveIds.map((id) => String(id)));
  relevant = allMatches.filter((item) => {
    const row = item.json || {};
    const mid = String(row.match_id || "").trim();
    return mid && idSet.has(mid);
  });

  console.log(
    `[Filter Active Only] Using match IDs from webhook: ${liveIds.join(", ")} -> matched ${relevant.length} rows in watchlist.`
  );

  if (relevant.length < liveIds.length) {
    const foundIds = new Set(relevant.map(item => String(item.json.match_id)));
    const notFoundIds = liveIds.filter(id => !foundIds.has(id));
    console.log(`[Filter Active Only] WARNING: IDs not found in watchlist: ${notFoundIds.join(", ")}`);
  }
}

if (!relevant.length && liveIds.length === 0) {
  for (const item of allMatches) {
    const row = item.json || {};
    const dateStr = String(row.date || "").trim();
    const kickoffStr = String(row.kickoff || "").trim();
    const matchStart = parseLocalDateTime(dateStr, kickoffStr);
    if (!matchStart) continue;

    const matchEnd = new Date(matchStart.getTime() + MATCH_DURATION_MINUTES * 60000);
    const diffKickoffMinutes = (matchStart - nowLocal) / 60000;
    const diffEndMinutes = (matchEnd - nowLocal) / 60000;

    if (diffKickoffMinutes > FUTURE_WINDOW_MINUTES) continue;
    if (diffEndMinutes < -MATCH_END_GRACE_MINUTES) continue;

    relevant.push(item);
  }

  console.log(`[Filter Active Only] Fallback by date/kickoff -> matched ${relevant.length} rows.`);
}

if (!relevant.length) {
  console.log("[Filter Active Only] No matches in watchlist need checking at this time.");
  return [];
}

// ============================================================
// NEW: Attach force_analyze flag to each item
// ============================================================
return relevant.map(item => ({
  json: {
    ...item.json,
    force_analyze: forceAnalyze,
    is_manual_push: isManualPush,
  }
}));

const matches = $input.all();
const config = $('Set Config').first().json;
if (matches.length === 0) throw new Error('No matches');

return matches.map((item) => {
  const match = item.json;
  return { 
    json: { 
      config, 
      match_id: match.match_id, 
      home_team: match.home_team, 
      away_team: match.away_team, 
      league: match.league, 
      mode: match.mode || 'B', 
      custom_conditions: match.custom_conditions || '', 
      priority: match.priority || 3,
      prediction: match.prediction || '',
      // ============================================================
      // NEW: Pass through force_analyze and is_manual_push flags
      // ============================================================
      force_analyze: match.force_analyze || false,
      is_manual_push: match.is_manual_push || false,
      recommended_custom_condition: match.recommended_custom_condition || '',
      recommended_condition_reason: match.recommended_condition_reason || '',
      recommended_condition_reason_vi: match.recommended_condition_reason_vi || '',
    } 
  };
});

const items = $input.all();
if (!items.length) throw new Error('No matches');
const matchMap = new Map();
for (const item of items) {
  const m = item.json;
  const id = String(m.match_id || '').trim();
  if (id && !matchMap.has(id)) matchMap.set(id, { ...m, match_id: id });
}
const matches = Array.from(matchMap.values());
if (!matches.length) throw new Error('No valid match_id');
const batches = [];
for (let i = 0; i < matches.length; i += 20) {
  const chunk = matches.slice(i, i + 20);
  batches.push({ json: { ids: chunk.map(m => m.match_id).join('-'), matches: chunk } });
}
return batches;

const batchItems = $('Build Fixtures Batch').all();
const responseItems = $input.all();
if (!responseItems.length) throw new Error('No HTTP response');

const allMatches = [];
for (const batch of batchItems) {
  if (Array.isArray(batch.json?.matches)) allMatches.push(...batch.json.matches);
}

const allFixtures = [];
for (const item of responseItems) {
  const apiData = item.json || {};
  if (apiData.errors) {
    const err = apiData.errors.rateLimit || apiData.errors.ids || apiData.errors.requests;
    if (err) throw new Error(`API Error: ${err}`);
  }
  allFixtures.push(...(apiData.response || []));
}

const fixtureMap = new Map();
for (const fx of allFixtures) {
  const id = fx?.fixture?.id;
  if (id) fixtureMap.set(String(id), fx);
}

const getStatValue = (teamStats, statName) => {
  if (!Array.isArray(teamStats)) return null;
  const stat = teamStats.find(s => s.type === statName);
  return stat?.value != null ? String(stat.value) : null;
};

const twoSideStat = (homeStats, awayStats, statName) => {
  const h = getStatValue(homeStats, statName) ?? '';
  const a = getStatValue(awayStats, statName) ?? '';
  return `${h}-${a}`;
};

const parsePreMatchPrediction = (predictionRaw) => {
  if (!predictionRaw) return null;
  if (typeof predictionRaw === 'object' && predictionRaw !== null) return predictionRaw;
  if (typeof predictionRaw === 'string') {
    const trimmed = predictionRaw.trim();
    if (!trimmed || trimmed === '{}') return null;
    try {
      return JSON.parse(trimmed);
    } catch (e) {
      console.log(`⚠️ Failed to parse pre_match_prediction: ${e.message}`);
      return null;
    }
  }
  return null;
};

const buildPreMatchSummary = (prediction) => {
  if (!prediction) return '';
  const parts = [];
  const pred = prediction.predictions || {};
  const comp = prediction.comparison || {};
  if (pred.advice) parts.push(pred.advice);
  if (pred.winner?.name) parts.push(`Favourite: ${pred.winner.name}`);
  if (pred.percent) {
    const p = pred.percent;
    parts.push(`H${p.home || '?'} D${p.draw || '?'} A${p.away || '?'}`);
  }
  if (comp.total?.home && comp.total?.away) {
    parts.push(`Rating: ${comp.total.home} vs ${comp.total.away}`);
  }
  return parts.join(' | ');
};

const outputs = [];
for (const match of allMatches) {
  const matchId = String(match.match_id);
  const fx = fixtureMap.get(matchId);
  if (!fx) continue;

  const status = fx.fixture?.status?.short || 'NS';
  const minute = fx.fixture?.status?.elapsed ?? (status === 'FT' ? 90 : 0);
  const homeGoals = fx.goals?.home ?? 0;
  const awayGoals = fx.goals?.away ?? 0;

  const statsArr = fx.statistics || [];
  const homeStats = statsArr[0]?.statistics || [];
  const awayStats = statsArr[1]?.statistics || [];

  const stats = {
    possession: twoSideStat(homeStats, awayStats, 'Ball Possession'),
    shots: twoSideStat(homeStats, awayStats, 'Total Shots'),
    shots_on_target: twoSideStat(homeStats, awayStats, 'Shots on Goal'),
    shots_off_target: twoSideStat(homeStats, awayStats, 'Shots off Goal'),
    corners: twoSideStat(homeStats, awayStats, 'Corner Kicks'),
    fouls: twoSideStat(homeStats, awayStats, 'Fouls'),
    yellow_cards: twoSideStat(homeStats, awayStats, 'Yellow Cards'),
    red_cards: twoSideStat(homeStats, awayStats, 'Red Cards'),
    saves: twoSideStat(homeStats, awayStats, 'Goalkeeper Saves'),
  };

  const parseTwoSide = (v) => {
    if (!v) return { home: null, away: null };
    const parts = String(v).split('-');
    const h = (parts[0] || '').trim() || null;
    const a = (parts[1] || '').trim() || null;
    return { home: h, away: a };
  };

  const statsCompact = {
    possession: parseTwoSide(stats.possession),
    shots: parseTwoSide(stats.shots),
    shots_on_target: parseTwoSide(stats.shots_on_target),
    shots_off_target: parseTwoSide(stats.shots_off_target),
    corners: parseTwoSide(stats.corners),
    fouls: parseTwoSide(stats.fouls),
    yellow_cards: parseTwoSide(stats.yellow_cards),
    red_cards: parseTwoSide(stats.red_cards),
    saves: parseTwoSide(stats.saves),
  };

  const rawEvents = Array.isArray(fx.events) ? fx.events : [];
  const homeName = fx.teams?.home?.name || match.home_team || 'Home';
  const awayName = fx.teams?.away?.name || match.away_team || 'Away';
  const leagueName = fx.league?.name || match.league || 'Unknown league';
  const homeTeamId = fx.teams?.home?.id;
  const awayTeamId = fx.teams?.away?.id;

  const summaryPieces = [];
  const compactEvents = [];

  let goalsHomeEv = 0, goalsAwayEv = 0;
  for (const ev of rawEvents.sort((a, b) => (a.time?.elapsed || 0) - (b.time?.elapsed || 0))) {
    const m = ev.time?.elapsed;
    const type = ev.type || '';
    const detail = ev.detail || '';
    const teamId = ev.team?.id;
    let side = teamId === homeTeamId ? 'home' : (teamId === awayTeamId ? 'away' : 'unknown');
    let sideName = side === 'home' ? homeName : (side === 'away' ? awayName : ev.team?.name || '');

    if (type === 'Goal') {
      if (side === 'home') goalsHomeEv++; else if (side === 'away') goalsAwayEv++;
      summaryPieces.push(`${m}'Goal ${sideName} ${goalsHomeEv}-${goalsAwayEv}`);
      compactEvents.push({
        minute: m ?? null,
        type: 'goal',
        side,
        team: sideName,
        score: `${goalsHomeEv}-${goalsAwayEv}`,
      });
    }
    if (type === 'Card') {
      summaryPieces.push(`${m}'${detail} ${sideName}`);
      compactEvents.push({
        minute: m ?? null,
        type: 'card',
        side,
        team: sideName,
        detail,
      });
    }
  }

  const preMatchPrediction = parsePreMatchPrediction(match.prediction);
  const preMatchPredictionSummary = buildPreMatchSummary(preMatchPrediction);

  outputs.push({
    json: {
      config: match.config, 
      match_id: match.match_id, 
      mode: match.mode, 
      custom_conditions: match.custom_conditions,
      priority: match.priority ?? null,
      // ============================================================
      // NEW: Pass through force_analyze and is_manual_push flags
      // ============================================================
      force_analyze: match.force_analyze || false,
      is_manual_push: match.is_manual_push || false,
      recommended_custom_condition: match.recommended_custom_condition || '',
      recommended_condition_reason: match.recommended_condition_reason || '',
      recommended_condition_reason_vi: match.recommended_condition_reason_vi || '',
      match: { 
        home: homeName, 
        away: awayName, 
        league: leagueName, 
        minute, 
        score: `${homeGoals}-${awayGoals}`, 
        status 
      },
      stats,
      stats_compact: statsCompact,
      events_summary: summaryPieces.slice(-4).join(' | '),
      events_compact: compactEvents.slice(-4),
      pre_match_prediction: preMatchPrediction,
      pre_match_prediction_summary: preMatchPredictionSummary,
    },
  });
}

if (!outputs.length) throw new Error('No merged matches');
return outputs;

// Check Should Proceed v3
// NEW: Support force_analyze to bypass all filters

const item = $json || {};
const config = item.config || {};
const match = item.match || {};
const stats = item.stats || {};

// ============================================================
// NEW: Check force_analyze flag
// ============================================================
const forceAnalyze = item.force_analyze === true;
const isManualPush = item.is_manual_push === true;

const statusRaw = String(match.status || '').toUpperCase();
const minute = Number(match.minute ?? 0) || 0;

const MIN_MINUTE = Number(config.MIN_MINUTE ?? 5);
const MAX_MINUTE = Number(config.MAX_MINUTE ?? 85);
const SECOND_HALF_START_MINUTE = Number(config.SECOND_HALF_START_MINUTE ?? 5);

let shouldProceed = true;
const reasons = [];
const skippedFilters = [];

const LIVE_STATUSES = ['1H', '2H'];

// ============================================================
// FILTER 1: Status check
// ============================================================
if (!LIVE_STATUSES.includes(statusRaw)) {
  if (forceAnalyze) {
    skippedFilters.push(`Status ${statusRaw || 'UNKNOWN'} not live (BYPASSED by force)`);
    console.log(`[Check Should Proceed] FORCE: Bypassing status check for ${statusRaw}`);
  } else {
    shouldProceed = false;
    reasons.push(`Status ${statusRaw || 'UNKNOWN'} not live`);
  }
}

// ============================================================
// FILTER 2: Minute window check
// ============================================================
if (shouldProceed || forceAnalyze) {
  let effectiveMinMinute = MIN_MINUTE;

  if (statusRaw === '2H') {
    const secondHalfThreshold = 45 + SECOND_HALF_START_MINUTE;
    if (secondHalfThreshold > effectiveMinMinute) {
      effectiveMinMinute = secondHalfThreshold;
    }
  }

  if (minute < effectiveMinMinute) {
    if (forceAnalyze) {
      skippedFilters.push(`Minute ${minute}' below minimum (${effectiveMinMinute}') (BYPASSED)`);
      console.log(`[Check Should Proceed] FORCE: Bypassing minute minimum check`);
    } else if (shouldProceed) {
      shouldProceed = false;
      reasons.push(`Minute ${minute}' below minimum window (${effectiveMinMinute}')`);
    }
  }

  if (minute > MAX_MINUTE) {
    if (forceAnalyze) {
      skippedFilters.push(`Minute ${minute}' beyond maximum (${MAX_MINUTE}') (BYPASSED)`);
      console.log(`[Check Should Proceed] FORCE: Bypassing minute maximum check`);
    } else if (shouldProceed) {
      shouldProceed = false;
      reasons.push(`Minute ${minute}' beyond maximum window (${MAX_MINUTE}')`);
    }
  }
}

// ============================================================
// FILTER 3: Stats quality check
// ============================================================
const fields = [
  stats.possession,
  stats.shots,
  stats.shots_on_target,
  stats.corners,
  stats.fouls,
];

let total = 0;
let missing = 0;

for (const v of fields) {
  if (v === undefined) continue;
  total++;
  const s = String(v).trim();
  if (!s || s === '-' || s.toUpperCase() === 'NA') missing++;
}

const missing_ratio = total ? Number((missing / total).toFixed(2)) : 1;
let stats_quality = 'UNKNOWN';
if (missing_ratio > 0.75) stats_quality = 'VERY_POOR';
else if (missing_ratio > 0.5) stats_quality = 'POOR';
else if (missing_ratio > 0.25) stats_quality = 'FAIR';
else stats_quality = 'GOOD';

const stats_available = stats_quality === 'GOOD' || stats_quality === 'FAIR';

// ============================================================
// FILTER 4: Early game with poor stats
// ============================================================
if (
  (shouldProceed || forceAnalyze) &&
  LIVE_STATUSES.includes(statusRaw) &&
  minute < 15 &&
  (stats_quality === 'POOR' || stats_quality === 'VERY_POOR')
) {
  if (forceAnalyze) {
    skippedFilters.push('Early game with poor stats (BYPASSED)');
    console.log(`[Check Should Proceed] FORCE: Bypassing early game stats check`);
  } else if (shouldProceed) {
    shouldProceed = false;
    reasons.push('Early game with poor stats');
  }
}

// ============================================================
// FINAL DECISION
// ============================================================
const finalShouldProceed = forceAnalyze ? true : shouldProceed;

if (forceAnalyze && !shouldProceed) {
  console.log(`[Check Should Proceed] FORCE MODE: Would have been skipped due to: ${reasons.join(' | ')}`);
}

return {
  json: {
    ...item,
    stats_meta: {
      missing,
      total,
      missing_ratio,
      stats_quality,
    },
    stats_available,
    should_proceed: finalShouldProceed,
    proceed_reason: finalShouldProceed
      ? (forceAnalyze ? 'FORCE_ANALYZE' : 'LIVE_IN_WINDOW')
      : reasons.join(' | '),
    // ============================================================
    // NEW: Track force mode info
    // ============================================================
    force_analyze: forceAnalyze,
    is_manual_push: isManualPush,
    skipped_filters: skippedFilters,
    original_would_proceed: shouldProceed,
  },
};

// ===========================================================================
// Merge Odds to Match - PATCHED VERSION
// Giữ nguyên 100% logic gốc + thêm:
// 1. isHalfTimeMarket() filter
// 2. checkOddsSanity() validation
// ===========================================================================

function safeObj(v) {
  return v && typeof v === 'object' ? v : {};
}
function safeArr(v) {
  return Array.isArray(v) ? v : [];
}
function toNumber(v, def = null) {
  if (v === null || v === undefined) return def;
  if (typeof v === 'number') return isNaN(v) ? def : v;
  const n = Number(String(v).trim());
  return isNaN(n) ? def : n;
}

// ===========================================================================
// NEW: Half-time market detection
// ===========================================================================
function isHalfTimeMarket(betName) {
  const name = betName.toLowerCase();
  return (
    name.includes('1st half') ||
    name.includes('2nd half') ||
    name.includes('(1st half)') ||
    name.includes('(2nd half)') ||
    name.includes('first half') ||
    name.includes('second half') ||
    name.includes(' 1h') ||
    name.includes('1h ') ||
    name.includes(' 2h') ||
    name.includes('2h ') ||
    name.includes(' ht') ||
    name.endsWith(' ht') ||
    name.includes('half time') ||
    name.includes('halftime') ||
    name.includes('half-time') ||
    /\b1h\b/.test(name) ||
    /\b2h\b/.test(name) ||
    /\bht\b/.test(name)
  );
}

// ===========================================================================
// NEW: Sanity check for suspicious odds
// ===========================================================================
function checkOddsSanity(canonical, minute, scoreStr) {
  const warnings = [];
  const odds1x2 = canonical?.['1x2'];
  if (!odds1x2) return warnings;

  const { home, draw, away } = odds1x2;
  const parts = String(scoreStr || '0-0').split('-');
  const homeGoals = parseInt(parts[0], 10) || 0;
  const awayGoals = parseInt(parts[1], 10) || 0;

  // Late game sanity checks (minute >= 75)
  if (minute >= 75) {
    // Draw at level score in late game should have LOW odds (< 15), not high
    if (homeGoals === awayGoals && draw > 15) {
      warnings.push(`SANITY_FAIL: Draw @${draw} at ${minute}' with ${scoreStr} is unrealistic`);
    }

    // Team leading by 2+ goals should have very low odds (< 5)
    if (homeGoals >= awayGoals + 2 && home > 5) {
      warnings.push(`SANITY_FAIL: Home @${home} leading 2+ at ${minute}' is unrealistic`);
    }
    if (awayGoals >= homeGoals + 2 && away > 5) {
      warnings.push(`SANITY_FAIL: Away @${away} leading 2+ at ${minute}' is unrealistic`);
    }

    // Leading team should have lower odds than trailing team
    if (homeGoals > awayGoals && home > away) {
      warnings.push(`SANITY_FAIL: Home leading but higher odds (H@${home} vs A@${away})`);
    }
    if (awayGoals > homeGoals && away > home) {
      warnings.push(`SANITY_FAIL: Away leading but higher odds (A@${away} vs H@${home})`);
    }
  }

  // Extremely high odds in late game (> 50) is suspicious
  if (minute >= 70 && (home > 50 || draw > 50 || away > 50)) {
    warnings.push(`SANITY_FAIL: Extreme odds (H@${home}, D@${draw}, A@${away}) at ${minute}'`);
  }

  return warnings;
}

// 1) Current odds HTTP response
const oddsResponse = safeObj($json);

// 2) Match data from "Should Proceed?" node, same item index
const idx = $itemIndex ?? 0;
let matchData = {};
try {
  const matchItems = $items('Should Proceed?', 0, 0);
  if (matchItems[idx]) {
    matchData = safeObj(matchItems[idx].json);
  }
} catch (e) {
  console.log('⚠️ Could not read from "Should Proceed?":', e.message);
}

// NEW: Extract minute for sanity check
const matchInfo = matchData.match || {};
const minute = matchInfo.minute ?? 0;

const scoreStr =
  (matchData.match && matchData.match.score) ||
  matchData.score ||
  '0-0';

const partsScore = String(scoreStr).split('-');
const homeGoals = parseInt(partsScore[0], 10) || 0;
const awayGoals = parseInt(partsScore[1], 10) || 0;
