// 4.x Build canonical odds snapshot for AI / logs (safe & compact)
const oddsCanonical = (() => {
  const canonical = {};

  // --- 1X2: từ liveOdds.match_winner ---
  if (liveOdds.match_winner) {
    canonical['1x2'] = {
      home: liveOdds.match_winner.home ?? null,
      draw: liveOdds.match_winner.draw ?? null,
      away: liveOdds.match_winner.away ?? null,
    };
  } else {
    canonical['1x2'] = null;
  }

  // Helper: build main line từ oddsMap theo regex
 const buildMainOU = (regexKey, regexParse) => {
    const entries = Object.entries(oddsMap || {}).filter(([k]) =>
      regexKey.test(k)
    );
    if (!entries.length) return null;

    const lineMap = new Map();
    for (const [k, odd] of entries) {
      const m = k.match(regexParse);
      if (!m) continue;
      const dir = m[1];         // over / under
      const lineStr = m[2];     // "2.5"
      const line = Number(lineStr);
      if (!Number.isFinite(line)) continue;

      const key = lineStr;
      if (!lineMap.has(key)) lineMap.set(key, {});
      const entry = lineMap.get(key);
      entry[dir] = Math.max(entry[dir] || 0, odd);
    }

    const sortedLines = Array.from(lineMap.keys())
      .map((s) => Number(s))
      .filter((n) => Number.isFinite(n))
      .sort((a, b) => Math.abs(a) - Math.abs(b));

    if (!sortedLines.length) return null;
    const bestLineStr = sortedLines[0].toString();
    const data = lineMap.get(bestLineStr) || {};
    return {
      line: Number(bestLineStr),
      over: data.over ?? null,
      under: data.under ?? null,
    };
  };

  const buildMainAH = () => {
    const entries = Object.entries(oddsMap || {}).filter(([k]) =>
      /^(home|away)\s+[-+]?[0-9]+(\.[0-9]+)?$/.test(k)
    );
    if (!entries.length) return null;

    const lineMap = new Map();
    for (const [k, odd] of entries) {
      const m = k.match(/^(home|away)\s+([-+]?[0-9]+(\.[0-9]+)?)/);
      if (!m) continue;
      const side = m[1];        // home / away
      const lineStr = m[2];     // "-0.25"
      const line = Number(lineStr);
      if (!Number.isFinite(line)) continue;

      const key = lineStr;
      if (!lineMap.has(key)) lineMap.set(key, {});
      const entry = lineMap.get(key);
     entry[side] = Math.max(entry[side] || 0, odd);
    }

    const sortedLines = Array.from(lineMap.keys())
      .map((s) => Number(s))
      .filter((n) => Number.isFinite(n))
      .sort((a, b) => Math.abs(a) - Math.abs(b));

    if (!sortedLines.length) return null;
   const bestLineStr = sortedLines[0].toString();
    const data = lineMap.get(bestLineStr) || {};
    return {
      line: Number(bestLineStr),
      home: data.home ?? null,
      away: data.away ?? null,
    };
  };

  // --- OU goals ---
  canonical['ou'] = buildMainOU(
    /^(over|under)\s+[0-9]+(\.[0-9]+)?$/,
    /^(over|under)\s+([0-9]+(\.[0-9]+)?)/
  );

  // --- Asian handicap ---
  canonical['ah'] = buildMainAH();

  // --- Corners OU ---
  canonical['corners_ou'] = buildMainOU(
    /^corners\s+(over|under)\s+[0-9]+(\.[0-9]+)?$/,
    /^corners\s+(over|under)\s+([0-9]+(\.[0-9]+)?)/
  );

  // --- BTTS ---
  if (liveOdds.btts) {
    canonical['btts'] = {
      yes: liveOdds.btts.yes ?? null,
      no: liveOdds.btts.no ?? null,
    };
  } else {
    canonical['btts'] = null;
  }
  return canonical;
})();


