function toNumber(val, fallback) {
  if (val === null || val === undefined) return fallback;
  const n = Number(val);
  return Number.isFinite(n) ? n : fallback;
}

function extractJsonString(text) {
  if (!text) return null;
  const s = String(text);
  let m = s.match(/```json([\s\S]*?)```/i);
  if (m && m[1]) return m[1].trim();
  m = s.match(/```([\s\S]*?)```/);
  if (m && m[1]) return m[1].trim();
  const first = s.indexOf("{");
  const last = s.lastIndexOf("}");
  if (first >= 0 && last > first) {
    return s.slice(first, last + 1);
  }
  return null;
}

// ============================================================
// NEW: Improved odds extraction function
// ============================================================
function extractOddsFromSelection(selection, oddsMap, oddsCanonical) {
  if (!selection) return null;

  const sel = String(selection).toLowerCase().trim();

  // Method 1: Check if selection already contains @ price
  const priceMatch = sel.match(/@\s*([0-9]+\.?[0-9]*)/);
  if (priceMatch) {
    const price = parseFloat(priceMatch[1]);
    if (price > 1 && price < 100) return price;
  }

  // Method 2: Direct match in oddsMap
  const normalizedSel = sel.replace(/\s+/g, " ");
  if (oddsMap && oddsMap[normalizedSel]) {
    return parseFloat(oddsMap[normalizedSel]) || null;
  }

  // Method 3: Detect market type from selection and get from canonical
  const selLower = sel.toLowerCase();

  // 1X2 Markets
  if (oddsCanonical && oddsCanonical['1x2']) {
    const x = oddsCanonical['1x2'];

    // Home win patterns
    if (selLower.includes('home win') || 
        selLower.includes('(home)') || 
        selLower.includes('home)') ||
        selLower.match(/\bhome\b.*\bwin\b/) ||
        selLower.match(/\b1x2\b.*\bhome\b/) ||
        (selLower.includes('win') && !selLower.includes('away') && !selLower.includes('draw') && selLower.match(/^[^@]*win/))) {
      if (x.home && x.home > 1) return x.home;
    }

    // Away win patterns  
    if (selLower.includes('away win') || 
        selLower.includes('(away)') ||
        selLower.includes('away)') ||
        selLower.match(/\baway\b.*\bwin\b/)) {
      if (x.away && x.away > 1) return x.away;
    }

    // Draw patterns
    if (selLower.includes('draw') || selLower.includes('1x2 x')) {
      if (x.draw && x.draw > 1) return x.draw;
    }
  }

  // Over/Under Markets
  if (oddsCanonical && oddsCanonical['ou']) {
    const ou = oddsCanonical['ou'];

    const overMatch = selLower.match(/over\s+([0-9]+\.?[0-9]*)/);
    if (overMatch) {
      const line = parseFloat(overMatch[1]);
      if (ou.line === line && ou.over > 1) return ou.over;
      if (oddsMap) {
        const ouKey = `over ${overMatch[1]}`;
        if (oddsMap[ouKey]) return parseFloat(oddsMap[ouKey]);
      }
    }

    const underMatch = selLower.match(/under\s+([0-9]+\.?[0-9]*)/);
    if (underMatch) {
      const line = parseFloat(underMatch[1]);
      if (ou.line === line && ou.under > 1) return ou.under;
      if (oddsMap) {
        const ouKey = `under ${underMatch[1]}`;
        if (oddsMap[ouKey]) return parseFloat(oddsMap[ouKey]);
      }
    }
  }

  // BTTS Markets
  if (oddsCanonical && oddsCanonical['btts']) {
    const btts = oddsCanonical['btts'];

    if (selLower.includes('btts yes') || selLower.includes('both teams to score yes') || 
        (selLower.includes('btts') && selLower.includes('yes'))) {
      if (btts.yes && btts.yes > 1) return btts.yes;
    }
    if (selLower.includes('btts no') || selLower.includes('both teams to score no') ||
        (selLower.includes('btts') && selLower.includes('no'))) {
      if (btts.no && btts.no > 1) return btts.no;
    }
  }

  // Simple key matching as fallback
  if (oddsMap) {
    const simpleKeys = ['home', 'away', 'draw'];
    for (const key of simpleKeys) {
      if (selLower.includes(key) && oddsMap[key]) {
        return parseFloat(oddsMap[key]) || null;
      }
    }
  }

  return null;
}

