      } else if (ctReasoningEn) {
        lines.push(`<i>${safeHtml(ctReasoningEn)}</i>`);
      }
    } else if (ctSuggestion && ctSuggestion.toLowerCase().includes("no bet")) {
      // Condition matched but AI says no bet
      lines.push("");
      lines.push("💰 <b>ĐỀ XUẤT:</b> Không đặt cược");
      if (ctReasoningVi) {
        lines.push(`<i>${safeHtml(ctReasoningVi)}</i>`);
      } else if (ctReasoningEn) {
        lines.push(`<i>${safeHtml(ctReasoningEn)}</i>`);
      }
    } else {
      // Condition matched but no specific suggestion
      lines.push("ℹ️ Điều kiện đã kích hoạt - xem xét cơ hội");
      if (ccReasonVi) {
        lines.push(`<i>${safeHtml(ccReasonVi)}</i>`);
      } else if (ccReasonEn) {
        lines.push(`<i>${safeHtml(ccReasonEn)}</i>`);
      }
    }
  }

  // =============================================================
  // SECTION 3: No actionable idea
  // =============================================================
  if (!hasAiIdea && !ccMatched) {
    lines.push("🎯 No actionable idea from AI.");

    if (reasoningVi) {
      lines.push(`<i>${safeHtml(reasoningVi)}</i>`);
    } else if (reasoningEn) {
      lines.push(`<i>${safeHtml(reasoningEn)}</i>`);
    }
  }

  // Warnings (if no AI idea)
  if (!hasAiIdea && warningsArr.length) {
    lines.push(
      `ℹ️ Notes: ${safeHtml(warningsArr.join(" | "))}`
    );
  }

  // Stats
  const stats = d.stats || {};
  const statsParts = [];
  if (stats.possession && stats.possession !== "-") {
    statsParts.push(`Poss ${stats.possession}`);
  }
  if (stats.shots_on_target && stats.shots_on_target !== "-") {
    statsParts.push(`SoT ${stats.shots_on_target}`);
  }
  if (stats.shots && stats.shots !== "-") {
    statsParts.push(`Shots ${stats.shots}`);
  }
  if (stats.corners && stats.corners !== "-") {
    statsParts.push(`Corners ${stats.corners}`);
  }

  if (statsParts.length) {
    lines.push(`📊 ${statsParts.join(" · ")}`);
  }

  if (eventsSummary) {
    lines.push(`📌 ${safeHtml(eventsSummary)}`);
  }

  lines.push("────────────────────────────────────");
}

// Disclaimer
lines.push(
  "⚠️ AI suggestions are for information only. Verify carefully before any decision."
);

// Ghép thành text lớn rồi cắt nếu quá dài
const MAX_LEN = 3500; // < 4096 để an toàn
const allText = lines.join("\n");

if (allText.length <= MAX_LEN) {
  return [{ json: { text: allText } }];
}

// Nếu dài quá -> chia thành nhiều message theo dòng
const chunks = [];
let current = "";

for (const line of lines) {
  const candidate = current ? current + "\n" + line : line;
  if (candidate.length > MAX_LEN && current) {
    chunks.push(current);
    current = line;
  } else {
    current = candidate;
  }
}
if (current.trim()) {
  chunks.push(current);
}

// Trả về nhiều item, node Telegram sẽ gửi nhiều tin nhắn
return chunks.map((t) => ({
  json: {
    text: t,
  },
}));

